import { useState } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function AddCourse() {
  const [courseName, setCourseName] = useState("");
  const user = useSelector((state) => state.auth.user);

  async function handleSubmit() {
    if (!courseName) {
      toast.error("Введите название курса!");
      return;
    }

    try {
      // 1. Создаем новый предмет автоматически
      const newSubject = {
        name: `${courseName} - Учитель ${user.name}`,
      };
      const subjectResponse = await fetch("http://localhost:3001/subjects", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newSubject),
      });
      const subject = await subjectResponse.json();

      // 2. Связываем учителя с новым предметом
      const newTeacherSubject = {
        teacherId: user.id,
        subjectId: subject.id,
      };
      await fetch("http://localhost:3001/teacher_subjects", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newTeacherSubject),
      });

      // 3. Создаем курс с новым предметом
      const newCourse = {
        name: courseName,
        teacherId: user.id,
        subjectId: subject.id,
      };
      const courseResponse = await fetch("http://localhost:3001/courses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newCourse),
      });

      if (courseResponse.ok) {
        toast.success("Курс и предмет созданы!");
        setCourseName("");
      } else {
        toast.error("Ошибка при создании курса");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
  }

  if (!user || user.role !== "teacher") {
    return <div>Доступ только для учителей</div>;
  }

  return (
    <div>
      <h2>Создать курс</h2>
      <input
        type="text"
        value={courseName}
        onChange={(e) => setCourseName(e.target.value)}
        placeholder="Название курса"
      />
      <button onClick={handleSubmit}>Создать</button>
    </div>
  );
}

export default AddCourse;
